/**
 * Helper function to check if a single number x is a "good" integer.
 * @param {number} x - The integer to check.
 * @param {string} directions - The direction string.
 * @returns {boolean} True if x is good, false otherwise.
 */
const isGood = (x, directions) => {
    // 1. Format x to 16 digits string S
    let s = String(x);
    // Pad with leading zeros to ensure 16 digits
    while (s.length < 16) {
        s = '0' + s;
    }

    // 2. Populate 4x4 grid G
    // G[row][col] stores the digit value (0-9)
    const G = Array(4).fill(0).map(() => Array(4).fill(0));
    for (let i = 0; i < 16; i++) {
        const row = Math.floor(i / 4);
        const col = i % 4;
        // Convert character digit to number
        G[row][col] = parseInt(s[i]);
    }

    // 3. Determine the path and record sequence P
    let r = 0;
    let c = 0;
    const P = [];

    // Start cell (Position 0)
    P.push(G[r][c]); 

    // Apply 6 directions (Positions 1 through 6)
    for (let i = 0; i < 6; i++) {
        const direction = directions[i];

        if (direction === 'D') {
            r += 1;
        } else if (direction === 'R') {
            c += 1;
        }

        // Record the digit at the new position
        P.push(G[r][c]);
    }

    // 4. Check for non-decreasing property
    // P has length 7. Check P[i] >= P[i-1] for i=1 to 6.
    for (let i = 1; i < 7; i++) {
        if (P[i] < P[i - 1]) {
            return false;
        }
    }

    return true;
};


const solve = (l, r, directions) => {
    let count = 0;

    // Iterate through the range [l, r] and count good integers.
    // Since l and r are within the safe integer limit (9 * 10^15 < 2^53), standard Number iteration is used.
    for (let x = l; x <= r; x++) {
        if (isGood(x, directions)) {
            count++;
        }
    }

    return count;
};

